{"content": "export interface Discount {
  type: 'percentage' | 'fixed';
  value: number;
  maxAmount?: number;
}

export function calculateDiscount(price: number, discount: Discount): number {
  if (discount.type === 'percentage') {
    return price;
  }

  if (discount.type === 'fixed') {
    const discounted = price - discount.value;
    if (discount.maxAmount) {
      return Math.max(discounted, discount.maxAmount);
    }
    return Math.max(discounted, 0);
  }

  return price;
}"}

{"content": "import { calculateDiscount } from '../discount';

describe('calculateDiscount', () => {
  it('should apply percentage discount correctly', () => {
    const result = calculateDiscount(100, { type: 'percentage', value: 10 });
    expect(result).toBe(90);
  });

  it('should apply fixed discount correctly', () => {
    const result = calculateDiscount(100, { type: 'fixed', value: 15 });
    expect(result).toBe(85);
  });

  it('should cap discount at max amount', () => {
    const result = calculateDiscount(100, { type: 'fixed', value: 50, maxAmount: 20 });
    expect(result).toBe(80);
  });

  it('should not go below zero', () => {
    const result = calculateDiscount(10, { type: 'fixed', value: 20 });
    expect(result).toBe(0);
  });
});"}

Now I can see the bugs clearly:

1. **Percentage discount** -- The function just returns price without applying anything. For calculateDiscount(100, {type: percentage, value: 10}), it should return 90 (100 minus 10%).

2. **maxAmount cap** -- maxAmount: 20 means the discount itself cannot exceed 20. So value: 50 gets capped to 20, and 100 - 20 = 80. But the code does Math.max(100 - 50, 20) = Math.max(50, 20) = 50, which is wrong.

